import{_ as s,o as i,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"6.2  Precision Strikes: Planting Landmines with the slub_debug Parameter","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch06_2.md","filePath":"en/notes/linux_kernel_debugging/ch06_2.md","lastUpdated":null}'),t={name:"en/notes/linux_kernel_debugging/ch06_2.md"};function l(o,e,r,h,p,d){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_6-2-precision-strikes-planting-landmines-with-the-slub-debug-parameter" tabindex="-1">6.2 Precision Strikes: Planting Landmines with the slub_debug Parameter <a class="header-anchor" href="#_6-2-precision-strikes-planting-landmines-with-the-slub-debug-parameter" aria-label="Permalink to &quot;6.2  Precision Strikes: Planting Landmines with the slub_debug Parameter&quot;">​</a></h1><p>In the previous section, we mentioned that the SLUB debugging mechanism is already locked and loaded (<code>CONFIG_SLUB_DEBUG</code>), but the safety is on by default.</p><p>Now, it&#39;s time to learn how to take off the safety and toss a few grenades into this memory minefield.</p><p>Our core tool is the kernel command-line parameter <strong><code>slub_debug</code></strong>. It allows us to finely control the enabling and disabling of debugging logic without recompiling the kernel or changing a single line of code. It&#39;s like targeting an area from an aircraft (a slab cache) and then deciding whether to drop leaflets (logs only) or drop bombs (forced crashes).</p><p>But before we drop any bombs, we need to take a look at the <strong>fuses</strong>.</p><h3 id="_6-2-1-breaking-down-slub-debug-your-arsenal" tabindex="-1">6.2.1 Breaking Down slub_debug: Your Arsenal <a class="header-anchor" href="#_6-2-1-breaking-down-slub-debug-your-arsenal" aria-label="Permalink to &quot;6.2.1  Breaking Down slub_debug: Your Arsenal&quot;">​</a></h3><p>The syntax of the <code>slub_debug</code> parameter is very intuitive, but it has many options. You can think of it as a row of toggle switches, each controlling a specific detection mechanism.</p><p>First, let&#39;s look at this official &quot;arsenal&quot;:</p><blockquote><p>[Insert translated or retained content from original Table 6.1]</p><ul><li><strong>F (Sanity checks)</strong>: Basic sanity checks. Verifies whether metadata is corrupted during allocation and freeing.</li><li><strong>Z (Red zoning)</strong>: Red zones. Fills specific areas before and after objects to catch out-of-bounds access.</li><li><strong>P (Poisoning)</strong>: Poisoning. Fills with specific magic numbers to catch Uninitialized Memory Reads (UMR) or Use-After-Free (UAF) errors.</li><li><strong>U (User tracking)</strong>: User tracking. Records who allocated/freed this object (saves stack traces).</li><li><strong>T (Trace)</strong>: Traces the allocation/freeing trajectory.</li><li><strong>A (Failure tracking)</strong>: Failure statistics, recording where allocations failed.</li></ul></blockquote><p>These switches can be used not only individually but also in combination. In addition, there is a very useful sysfs interface document (although it looks a bit dated): <code>Documentation/ABI/testing/sysfs-kernel-slab</code>.</p><p>But before diving into hands-on practice, we need to understand the most core concept—<strong>Poisoning</strong>. This is the &quot;true mirror&quot; that reveals most bizarre memory errors.</p><h3 id="_6-2-2-deep-dive-into-the-mechanics-those-strange-hex-numbers" tabindex="-1">6.2.2 Deep Dive into the Mechanics: Those Strange Hex Numbers <a class="header-anchor" href="#_6-2-2-deep-dive-into-the-mechanics-those-strange-hex-numbers" aria-label="Permalink to &quot;6.2.2  Deep Dive into the Mechanics: Those Strange Hex Numbers&quot;">​</a></h3><p>How does the SLUB debugging mechanism know which memory you&#39;ve touched? It relies on &quot;dyeing.&quot;</p><p>The kernel defines several special dyes in <code>include/linux/poison.h</code>. We can think of memory as a canvas, and the kernel paints specific colors in specific spots on these canvases. If you alter these colors, the kernel knows you did it.</p><p>Let&#39;s look at the recipes for these colors (magic numbers):</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// include/linux/poison.h</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> POISON_INUSE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5a</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* for use-uninitialised poisoning (ASCII &#39;Z&#39;) */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> POISON_FREE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6b</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* for use-after-free poisoning (ASCII &#39;k&#39;) */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> POISON_END</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">a5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* end-byte of poisoning            */</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>These three macro definitions are the cornerstone of the entire poisoning mechanism. Let&#39;s break them down one by one:</p><ol><li><p><strong>POISON_FREE (0x6b)</strong>: This is the most commonly used &quot;poison.&quot; When you enable <code>slub_debug=P</code> or create a cache with the <code>SLAB_POISON</code> flag, the kernel fills the memory with <code>0x6b</code> (corresponding to the ASCII character <code>k</code>) after an object is freed, or right after it&#39;s allocated but before any data is written to it.</p><ul><li><strong>Meaning</strong>: This memory is now &quot;dead.&quot; If you read it, you should see a screen full of <code>0x6b</code>; if you see any other value, it means either you read it before initializing it (UMR), or you wrote to it after freeing it (UAF).</li></ul></li><li><p><strong>POISON_INUSE (0x5a)</strong>: This value is primarily used to fill the inside of red zones or for certain special state markers. If you see <code>0x5a</code> inside a red zone, it means this is a safe boundary; if it changes, it means you&#39;ve blown through the boundary.</p></li><li><p><strong>POISON_END (0xa5)</strong>: This is a sentinel. The last valid byte of each slab object is set to this value. It acts like a warning sign next to a landmine—once it&#39;s trampled (overwritten), the kernel immediately sounds the alarm.</p></li></ol><h3 id="_6-2-3-uninitialized-memory-reads-umr-erupting-in-silence" tabindex="-1">6.2.3 Uninitialized Memory Reads (UMR): Erupting in Silence <a class="header-anchor" href="#_6-2-3-uninitialized-memory-reads-umr-erupting-in-silence" aria-label="Permalink to &quot;6.2.3  Uninitialized Memory Reads (UMR): Erupting in Silence&quot;">​</a></h3><p>Just looking at the definitions is too abstract. Let&#39;s run an experiment using the test code <code>ch5/kmembugs_test.c</code> we wrote in Chapter 5.</p><p>The <code>umr_slub()</code> function inside is very simple (and very stupid): it requests 32 bytes of memory and then <strong>reads it directly without writing anything</strong>. This is a classic &quot;Uninitialized Memory Read&quot; (UMR).</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 代码逻辑示意 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">q </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kmalloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, GFP_KERNEL);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 故意不写 memset 或赋值 */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">printk</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;q[3] is 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">%x\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">q</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* 直接读垃圾值 */</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Scenario 1: No Debug Protection (Running Bare)</strong></p><p>If we run this test without any <code>slub_debug</code> parameter, what will the kernel log look like?</p><p>It will look roughly like this:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ 6845.100813] testcase to run: 10</span></span>
<span class="line"><span>[ 6845.101126] test_kmembugs:umr_slub(): testcase 10: simple UMR on slab memory</span></span>
<span class="line"><span>[ 6845.101771] test_kmembugs:umr_slub(): q[3] is 0x0</span></span>
<span class="line"><span>[ 6845.102203] q: 00000000: 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00  ................</span></span>
<span class="line"><span>[ 6845.102946] q: 00000010: 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00  ................</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>See that neat row of <code>00</code>?</p><p>This is extremely dangerous. Because it looks &quot;clean,&quot; as if this memory was initialized to 0. But this is purely coincidental—the kernel happened to give us a zeroed-out page (like a clean page reclaimed by the page allocator). <strong>If you rely on this &quot;coincidence,&quot; your code will inevitably crash in other environments or at other times, and this type of Bug is non-reproducible.</strong></p><p>Now, let&#39;s change our approach, enable debug mode, and run it again.</p><p><strong>Scenario 2: Enabling Poison (Poisoning Mode)</strong></p><p>Although we won&#39;t show the new output here (leaving some suspense), I can tell you the result: those 32 bytes will no longer be <code>00</code>, but will all turn into <code>6b</code>.</p><p>If you go read <code>q[3]</code>, you won&#39;t get <code>0x0</code>; you will get <code>0x6b6b6b6b</code>.</p><p>This creates a huge <strong>cognitive dissonance</strong>:</p><ul><li>Before: You thought you read a 0, happily continued using it, and as a result, three days later when a certain condition triggered, the program crashed thousands of lines away.</li><li>Now: You read a screen full of <code>k</code> (<code>0x6b</code>), and you immediately know: &quot;Oh, I forgot to initialize this memory.&quot;</li></ul><p>This is the power of SLUB debugging—<strong>it turns uncertain garbage values into definitive error flags.</strong></p><h3 id="_6-2-4-step-by-step-configuration-practical-syntax-for-slub-debug" tabindex="-1">6.2.4 Step-by-Step Configuration: Practical Syntax for slub_debug <a class="header-anchor" href="#_6-2-4-step-by-step-configuration-practical-syntax-for-slub-debug" aria-label="Permalink to &quot;6.2.4  Step-by-Step Configuration: Practical Syntax for slub_debug&quot;">​</a></h3><p>Now that we understand the mechanics, let&#39;s flip the switches.</p><p>As long as your kernel is configured with <code>CONFIG_SLUB_DEBUG=y</code> (which we confirmed in the previous chapter), you can pass the <code>slub_debug</code> parameter at boot.</p><p><strong>The syntax format is as follows:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slub_debug</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Flags</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SlabList</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Flags</strong>: Any combination of the letters we just mentioned, like <code>F</code>, <code>Z</code>, <code>P</code>, <code>U</code>, etc. For example, <code>FZPU</code>. Don&#39;t leave spaces; just concatenate them directly.</li><li><strong>SlabList</strong> (Optional): Specifies which exact cache name to debug. If left empty, it applies to <strong>all</strong> slab caches by default.</li></ul><p>A few typical usages:</p><ul><li><p><strong>Full enable (The relentless approach)</strong>: <code>slub_debug=FZPU</code></p><blockquote><p>This enables the full suite of checks for all caches. <strong>⚠️ Warning</strong>: This will slow down the system immensely, and memory overhead will skyrocket. Unless you are specifically reproducing a fault, don&#39;t do this in a production environment.</p></blockquote></li><li><p><strong>Precision strike (Targeting a specific cache)</strong>: <code>slub_debug=,kmalloc-256</code></p><blockquote><p>Note that the part before the comma is empty, meaning &quot;use default flags (which usually means none),&quot; but only for the <code>kmalloc-256</code> cache. If you want to enable P and Z for <code>kmalloc-256</code>: <code>slub_debug=PZ,kmalloc-256</code></p></blockquote></li><li><p><strong>Disable all (even though it&#39;s off by default)</strong>: <code>slub_debug=-</code></p></li></ul><p><strong>Practical Demo: Enabling Full Monitoring</strong></p><p>Suppose we need to reproduce an extremely tricky Bug and decide to enable red zones, poisoning, sanity checks, and user tracking for all caches. We need to modify the GRUB configuration and append the following to the kernel boot parameters:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slub_debug</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">FZPU</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Save, reboot, and enter the system.</p><p>Let&#39;s verify that it actually took effect. Check the kernel boot parameters:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/cmdline</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BOOT_IMAGE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/boot/vmlinuz-5.10.60-dbg02-gcc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> root</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">UUID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ro</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quiet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> splash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slub_debug=FZPU</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Great, the parameter was passed in. But this is just a boot command—did the kernel actually listen?</p><p>We need to look at the actual state of the slab cache under sysfs. Let&#39;s use <code>kmalloc-32</code> (the cache specifically for allocating 32-byte small objects) as our test subject.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> export</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SLAB=/sys/kernel/slab/kmalloc-32</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${SLAB}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/sanity_checks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${SLAB}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/red_zone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${SLAB}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/poison</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${SLAB}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/store_user</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>See those four <code>1</code>?</p><p>This means:</p><ul><li><code>sanity_checks</code> (F): <strong>ON</strong></li><li><code>red_zone</code> (Z): <strong>ON</strong></li><li><code>poison</code> (P): <strong>ON</strong></li><li><code>store_user</code> (U): <strong>ON</strong></li></ul><p>The memory allocator is now like a heavily armed security guard; every single byte going in or out will be thoroughly frisked.</p><p>The system is ready. Next, we&#39;ll throw our problematic test code into it and see how this mechanism reports errors.</p>`,57)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
